<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    background: #0f172a;
    color: #e2e8f0;
    min-height: 100vh;
    padding: 32px 24px;
  }

  h1 {
    text-align: center;
    font-size: 1.75rem;
    font-weight: 700;
    letter-spacing: -0.5px;
    margin-bottom: 32px;
    color: #f8fafc;
  }

  .add-area {
    display: flex;
    gap: 10px;
    justify-content: center;
    margin-bottom: 36px;
  }

  #new-card {
    width: 340px;
    padding: 10px 14px;
    border-radius: 8px;
    border: 1.5px solid #334155;
    background: #1e293b;
    color: #e2e8f0;
    font-size: 0.95rem;
    outline: none;
    transition: border-color 0.2s;
  }

  #new-card:focus { border-color: #6366f1; }

  #add-card {
    padding: 10px 20px;
    border-radius: 8px;
    border: none;
    background: #6366f1;
    color: #fff;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.2s, transform 0.1s;
  }

  #add-card:hover { background: #4f46e5; }
  #add-card:active { transform: scale(0.97); }

  .board {
    display: flex;
    gap: 20px;
    align-items: flex-start;
    justify-content: center;
    flex-wrap: wrap;
  }

  .column {
    background: #1e293b;
    border-radius: 14px;
    width: 300px;
    min-height: 480px;
    display: flex;
    flex-direction: column;
    border: 1.5px solid #334155;
    transition: border-color 0.2s;
  }

  .column.drag-over {
    border-color: #6366f1;
    background: #1e2d47;
  }

  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 16px 18px 14px;
    border-bottom: 1.5px solid #334155;
  }

  .col-header h2 {
    font-size: 0.9rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    color: #94a3b8;
  }

  #col-todo .col-header h2 { color: #818cf8; }
  #col-doing .col-header h2 { color: #fb923c; }
  #col-done .col-header h2 { color: #34d399; }

  .count {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 22px;
    height: 22px;
    padding: 0 6px;
    border-radius: 999px;
    font-size: 0.75rem;
    font-weight: 700;
    background: #0f172a;
    color: #94a3b8;
  }

  .card-container {
    padding: 14px 12px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    flex: 1;
  }

  .card {
    background: #0f172a;
    border: 1.5px solid #334155;
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    cursor: grab;
    transition: border-color 0.15s, box-shadow 0.15s, opacity 0.15s;
    user-select: none;
  }

  .card:hover {
    border-color: #475569;
    box-shadow: 0 4px 16px rgba(0,0,0,0.35);
  }

  .card.dragging {
    opacity: 0.4;
    cursor: grabbing;
  }

  .card-title {
    font-size: 0.9rem;
    line-height: 1.45;
    color: #e2e8f0;
    flex: 1;
    word-break: break-word;
  }

  .card-del {
    flex-shrink: 0;
    background: none;
    border: none;
    color: #475569;
    font-size: 1.1rem;
    line-height: 1;
    cursor: pointer;
    padding: 0 2px;
    border-radius: 4px;
    transition: color 0.15s;
    margin-top: 1px;
  }

  .card-del:hover { color: #f87171; }
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div class="add-area">
  <input id="new-card" type="text" placeholder="New card title…" maxlength="200">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo">
    <div class="col-header">
      <h2>To Do</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-doing">
    <div class="col-header">
      <h2>Doing</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-done">
    <div class="col-header">
      <h2>Done</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
</div>

<script>
  const STORAGE_KEY = 'kanban-board-v1';
  let draggingCard = null;

  function save() {
    const state = [];
    document.querySelectorAll('.column').forEach(col => {
      col.querySelectorAll('.card').forEach(card => {
        state.push({ id: card.dataset.id, title: card.dataset.title, col: col.id });
      });
    });
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  function updateCount(col) {
    col.querySelector('.count').textContent = col.querySelectorAll('.card').length;
  }

  function updateAllCounts() {
    document.querySelectorAll('.column').forEach(updateCount);
  }

  function makeCard(id, title) {
    const card = document.createElement('div');
    card.className = 'card';
    card.draggable = true;
    card.dataset.id = id;
    card.dataset.title = title;

    const span = document.createElement('span');
    span.className = 'card-title';
    span.textContent = title;

    const del = document.createElement('button');
    del.className = 'card-del';
    del.textContent = '×';
    del.title = 'Delete card';
    del.addEventListener('click', () => {
      const col = card.closest('.column');
      card.remove();
      updateCount(col);
      save();
    });

    card.appendChild(span);
    card.appendChild(del);

    card.addEventListener('dragstart', e => {
      draggingCard = card;
      card.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
      e.dataTransfer.setData('text/plain', id);
    });

    card.addEventListener('dragend', () => {
      card.classList.remove('dragging');
      draggingCard = null;
    });

    return card;
  }

  function addCardToColumn(colId, id, title) {
    const col = document.getElementById(colId);
    const container = col.querySelector('.card-container');
    container.appendChild(makeCard(id, title));
    updateCount(col);
  }

  document.querySelectorAll('.column').forEach(col => {
    col.addEventListener('dragover', e => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      col.classList.add('drag-over');
    });

    col.addEventListener('dragleave', e => {
      if (!col.contains(e.relatedTarget)) {
        col.classList.remove('drag-over');
      }
    });

    col.addEventListener('drop', e => {
      e.preventDefault();
      col.classList.remove('drag-over');
      if (!draggingCard) return;
      const fromCol = draggingCard.closest('.column');
      const container = col.querySelector('.card-container');
      container.appendChild(draggingCard);
      if (fromCol && fromCol !== col) updateCount(fromCol);
      updateCount(col);
      save();
    });
  });

  document.getElementById('add-card').addEventListener('click', () => {
    const input = document.getElementById('new-card');
    const title = input.value.trim();
    if (!title) return;
    const id = 'card-' + Date.now() + '-' + Math.random().toString(36).slice(2, 7);
    addCardToColumn('col-todo', id, title);
    input.value = '';
    save();
    input.focus();
  });

  document.getElementById('new-card').addEventListener('keydown', e => {
    if (e.key === 'Enter') document.getElementById('add-card').click();
  });

  // Load persisted state
  try {
    const saved = JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]');
    saved.forEach(({ id, title, col }) => {
      if (document.getElementById(col)) {
        addCardToColumn(col, id, title);
      }
    });
  } catch (e) {
    // ignore corrupt storage
  }
</script>
</body>
</html>
